 15→func makeHMACToken(t *testing.T, secret string, claims Claims) string {
 16→	t.Helper()
 17→	token := jwt.NewWithClaims(jwt.SigningMethodHS256, &claims)
 18→	s, err := token.SignedString([]byte(secret))
 19→	if err != nil {
 20→		t.Fatalf("sign token: %v", err)
 21→	}
 22→	return s
 23→}
