 25→func TestHMACValidator_ValidToken(t *testing.T) {
 26→	t.Parallel()
 27→	secret := "test-secret-key"
 28→	v := NewHMACValidator(secret)
 29→
 30→	claims := Claims{
 31→		RegisteredClaims: jwt.RegisteredClaims{
 32→			Subject:   "user-123",
 33→			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
 34→			IssuedAt:  jwt.NewNumericDate(time.Now()),
 35→		},
 36→		Email:      "user@example.com",
 37→		Roles:      []string{"admin"},
 38→		TeamID:     "team-1",
 39→		ClientType: "web",
 40→	}
 41→
 42→	tokenStr := makeHMACToken(t, secret, claims)
 43→	got, err := v.Validate(tokenStr)
 44→	if err != nil {
 45→		t.Fatalf("unexpected error: %v", err)
 46→	}
