package router

import (
	"io/fs"
	"log/slog"
	"net"
	"net/http"
	"sync/atomic"
	"time"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/extension"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/99designs/gqlgen/graphql/playground"
	"github.com/go-chi/chi/v5"
	chimiddleware "github.com/go-chi/chi/v5/middleware"
	"github.com/go-chi/httprate"
	"github.com/jackc/pgx/v5/pgxpool"

	"github.com/ketang/kapow/api/graph/generated"
	"github.com/ketang/kapow/api/graph/resolver"
	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/config"
	kapowhandler "github.com/ketang/kapow/api/internal/handler"
	kapowmcp "github.com/ketang/kapow/api/internal/mcp"
	kapowmiddleware "github.com/ketang/kapow/api/internal/middleware"
	kapowotel "github.com/ketang/kapow/api/internal/otel"
	"github.com/ketang/kapow/api/internal/preference"
	"github.com/ketang/kapow/api/internal/search"
	"github.com/ketang/kapow/api/internal/user"
)

// Deps holds the dependencies needed to construct the router.
type Deps struct {
	Config            *config.Config
	DB                *pgxpool.Pool
	Validator         auth.Validator
	Search            *search.Registry
	UserService       *user.Service
	PreferenceService *preference.Service

	// HTTPDetailConfig holds the hot-reloadable HTTP debug logging config.
	// A future admin endpoint can call .Store() to change settings at runtime.
	// If nil, New() initialises it from Config.
	HTTPDetailConfig *atomic.Pointer[kapowmiddleware.HTTPDetailConfig]

	// PrivateCIDRs restricts /private/* routes to these IP ranges.
	PrivateCIDRs []*net.IPNet

	// UI holds the embedded SPA filesystem. When non-nil, unmatched routes
	// serve the SPA (static files + index.html fallback).
	UI fs.FS
}

// New constructs the chi router with all middleware, routes, and handlers.
func New(deps Deps) http.Handler {
	r := chi.NewRouter()

	// Initialise hot-reloadable HTTP detail config if not provided.
	if deps.HTTPDetailConfig == nil {
		deps.HTTPDetailConfig = &atomic.Pointer[kapowmiddleware.HTTPDetailConfig]{}
		deps.HTTPDetailConfig.Store(kapowmiddleware.NewHTTPDetailConfig(deps.Config))
	}

	// Global middleware (applied to every request)
	if deps.Config.OTelEnabled {
		r.Use(kapowotel.Middleware("kapow-api"))
	}
	r.Use(kapowmiddleware.RequestID)
	r.Use(kapowmiddleware.Logging)
	r.Use(kapowmiddleware.Recovery)
	r.Use(kapowmiddleware.HTTPDetail(deps.HTTPDetailConfig))
	r.Use(chimiddleware.RealIP)
	r.Use(chimiddleware.StripSlashes)

	// Build gqlgen server
	gqlSrv := handler.New(generated.NewExecutableSchema(generated.Config{
		Resolvers: &resolver.Resolver{DB: deps.DB, Search: deps.Search, Preference: deps.PreferenceService},
	}))
	gqlSrv.AddTransport(transport.POST{})
	gqlSrv.AddTransport(transport.GET{})
	if deps.Config.GraphQLIntrospection {
		gqlSrv.Use(extension.Introspection{})
	}

	// GraphQL endpoint — optional auth (anonymous allowed, user provisioned if token present)
	r.Route("/graphql", func(r chi.Router) {
		r.Use(kapowmiddleware.OptionalAuth(deps.Validator))
		r.Use(kapowmiddleware.EnsureUser(deps.UserService))
		if deps.Config.RateLimitEnabled {
			r.Use(authRateLimitOverride(deps.Config.RateLimitGraphQLAuth))
			r.Use(httprate.Limit(
				deps.Config.RateLimitGraphQL,
				time.Minute,
				httprate.WithKeyFuncs(authOrIPKeyFunc),
			))
		}
		r.Post("/", gqlSrv.ServeHTTP)
		r.Get("/", gqlSrv.ServeHTTP)
	})

	// GraphQL Playground (dev only)
	if deps.Config.GraphQLPlayground {
		r.Get("/playground", playground.Handler("Kapow API", "/graphql"))
		slog.Info("router: GraphQL Playground enabled at /playground")
	}

	// CSV export endpoint — optional auth + rate limited
	r.Route("/api/export", func(r chi.Router) {
		r.Use(kapowmiddleware.OptionalAuth(deps.Validator))
		r.Use(kapowmiddleware.EnsureUser(deps.UserService))
		if deps.Config.RateLimitEnabled {
			r.Use(httprate.Limit(
				deps.Config.RateLimitExport,
				time.Minute,
				httprate.WithKeyFuncs(authOrIPKeyFunc),
			))
		}
		r.Get("/csv", kapowhandler.ExportCSV(deps.DB, deps.Search, deps.Config.MaxExportRows))
	})

	// Private (internal) routes — IP allowlisted
	r.Route("/private", func(r chi.Router) {
		if len(deps.PrivateCIDRs) > 0 {
			r.Use(kapowmiddleware.IPAllowlist(deps.PrivateCIDRs))
		}
		r.Get("/healthcheck", kapowhandler.Health(deps.DB))
		r.Get("/log-config", kapowhandler.LogConfig(deps.Config))
		r.Put("/log-config", kapowhandler.LogConfig(deps.Config))
	})

	// MCP (Model Context Protocol) endpoint — AI client integration
	// Protected with mandatory Auth middleware; unauthenticated requests
	// receive 401 with WWW-Authenticate header per MCP OAuth 2.1 spec.
	if deps.Config.MCPEnabled {
		r.Route("/mcp", func(r chi.Router) {
			r.Use(kapowmiddleware.Auth(deps.Validator))
			if deps.Config.RateLimitEnabled {
				r.Use(httprate.Limit(
					deps.Config.RateLimitMCP,
					time.Minute,
					httprate.WithKeyFuncs(authOrIPKeyFunc),
				))
			}
			r.Handle("/*", kapowmcp.NewHandler(deps.DB, deps.Search))
		})
		slog.Info("router: MCP endpoint enabled at /mcp")
	}

	// OAuth 2.1 Protected Resource Metadata (RFC 9728)
	r.Get("/.well-known/oauth-protected-resource", kapowhandler.ProtectedResourceMetadata(deps.Config))

	// Embedded SPA — serve static files and fall back to index.html
	if deps.UI != nil {
		r.NotFound(kapowhandler.SPAHandler(deps.UI).ServeHTTP)
		slog.Info("router: embedded SPA enabled")
	}

	slog.Info("router: initialized",
		"graphql_introspection", deps.Config.GraphQLIntrospection,
		"graphql_playground", deps.Config.GraphQLPlayground,
		"mcp_enabled", deps.Config.MCPEnabled,
		"rate_limit_enabled", deps.Config.RateLimitEnabled,
		"embedded_ui", deps.UI != nil,
	)

	return r
}

// authOrIPKeyFunc keys by user subject if authenticated, otherwise by client IP.
func authOrIPKeyFunc(r *http.Request) (string, error) {
	if claims := auth.GetClaims(r.Context()); claims != nil {
		return "user:" + claims.Subject, nil
	}
	return "ip:" + r.RemoteAddr, nil
}

// authRateLimitOverride returns middleware that raises the httprate request limit
// for authenticated users by setting WithRequestLimit in the request context.
func authRateLimitOverride(authLimit int) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			if auth.GetClaims(r.Context()) != nil {
				r = r.WithContext(httprate.WithRequestLimit(r.Context(), authLimit))
			}
			next.ServeHTTP(w, r)
		})
	}
}

