package handler

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"

	"github.com/ketang/kapow/api/internal/auth"
)

const testSecret = "test-dev-secret-256-bits-long!!"

func TestDevLogin(t *testing.T) {
	h := DevLogin(testSecret)
	validator := auth.NewHMACValidator(testSecret)

	t.Run("happy path with email only", func(t *testing.T) {
		body := `{"email":"alice@example.com"}`
		req := httptest.NewRequest(http.MethodPost, "/dev/auth/login", strings.NewReader(body))
		rec := httptest.NewRecorder()

		h.ServeHTTP(rec, req)

		if rec.Code != http.StatusOK {
			t.Fatalf("expected 200, got %d: %s", rec.Code, rec.Body.String())
		}

		var resp devLoginResponse
		if err := json.NewDecoder(rec.Body).Decode(&resp); err != nil {
			t.Fatalf("decode response: %v", err)
		}
		if resp.TokenType != "bearer" {
			t.Errorf("token_type = %q, want %q", resp.TokenType, "bearer")
		}
		if resp.ExpiresIn != 86400 {
			t.Errorf("expires_in = %d, want 86400", resp.ExpiresIn)
		}

		// Validate the token with the same secret
		claims, err := validator.Validate(resp.AccessToken)
		if err != nil {
			t.Fatalf("token validation failed: %v", err)
		}
		if claims.Email != "alice@example.com" {
			t.Errorf("email = %q, want %q", claims.Email, "alice@example.com")
		}
		if claims.Role != "authenticated" {
			t.Errorf("role = %q, want %q", claims.Role, "authenticated")
		}
		if claims.Issuer != "kapow-dev" {
			t.Errorf("issuer = %q, want %q", claims.Issuer, "kapow-dev")
		}
		if claims.Provider() != "dev" {
			t.Errorf("provider = %q, want %q", claims.Provider(), "dev")
		}
		if claims.Subject == "" {
			t.Error("subject should be auto-generated, got empty")
		}
	})

	t.Run("with all fields", func(t *testing.T) {
		body := `{"email":"bob@example.com","name":"Bob Smith","sub":"custom-sub-123"}`
		req := httptest.NewRequest(http.MethodPost, "/dev/auth/login", strings.NewReader(body))
		rec := httptest.NewRecorder()

		h.ServeHTTP(rec, req)

		if rec.Code != http.StatusOK {
			t.Fatalf("expected 200, got %d: %s", rec.Code, rec.Body.String())
		}

		var resp devLoginResponse
		if err := json.NewDecoder(rec.Body).Decode(&resp); err != nil {
			t.Fatalf("decode response: %v", err)
		}

		claims, err := validator.Validate(resp.AccessToken)
		if err != nil {
			t.Fatalf("token validation failed: %v", err)
		}
		if claims.Subject != "custom-sub-123" {
			t.Errorf("subject = %q, want %q", claims.Subject, "custom-sub-123")
		}
		if claims.Email != "bob@example.com" {
			t.Errorf("email = %q, want %q", claims.Email, "bob@example.com")
		}
		name, _ := claims.UserMetadata["full_name"].(string)
		if name != "Bob Smith" {
			t.Errorf("full_name = %q, want %q", name, "Bob Smith")
		}
	})

	t.Run("missing email returns 400", func(t *testing.T) {
		body := `{"name":"No Email"}`
		req := httptest.NewRequest(http.MethodPost, "/dev/auth/login", strings.NewReader(body))
		rec := httptest.NewRecorder()

		h.ServeHTTP(rec, req)

		if rec.Code != http.StatusBadRequest {
			t.Fatalf("expected 400, got %d", rec.Code)
		}
	})

	t.Run("invalid JSON returns 400", func(t *testing.T) {
		req := httptest.NewRequest(http.MethodPost, "/dev/auth/login", strings.NewReader("not json"))
		rec := httptest.NewRecorder()

		h.ServeHTTP(rec, req)

		if rec.Code != http.StatusBadRequest {
			t.Fatalf("expected 400, got %d", rec.Code)
		}
	})

	t.Run("deterministic sub for same email", func(t *testing.T) {
		body := `{"email":"deterministic@example.com"}`

		req1 := httptest.NewRequest(http.MethodPost, "/dev/auth/login", strings.NewReader(body))
		rec1 := httptest.NewRecorder()
		h.ServeHTTP(rec1, req1)

		req2 := httptest.NewRequest(http.MethodPost, "/dev/auth/login", strings.NewReader(body))
		rec2 := httptest.NewRecorder()
		h.ServeHTTP(rec2, req2)

		var resp1, resp2 devLoginResponse
		_ = json.NewDecoder(rec1.Body).Decode(&resp1)
		_ = json.NewDecoder(rec2.Body).Decode(&resp2)

		claims1, _ := validator.Validate(resp1.AccessToken)
		claims2, _ := validator.Validate(resp2.AccessToken)

		if claims1.Subject != claims2.Subject {
			t.Errorf("same email should produce same sub: %q != %q", claims1.Subject, claims2.Subject)
		}
	})

	t.Run("audience claim is authenticated", func(t *testing.T) {
		body := `{"email":"aud@example.com"}`
		req := httptest.NewRequest(http.MethodPost, "/dev/auth/login", strings.NewReader(body))
		rec := httptest.NewRecorder()
		h.ServeHTTP(rec, req)

		var resp devLoginResponse
		_ = json.NewDecoder(rec.Body).Decode(&resp)
		claims, _ := validator.Validate(resp.AccessToken)

		aud, err := claims.GetAudience()
		if err != nil {
			t.Fatalf("get audience: %v", err)
		}
		if len(aud) != 1 || aud[0] != "authenticated" {
			t.Errorf("audience = %v, want [authenticated]", aud)
		}
	})
}

func TestDeterministicUUID(t *testing.T) {
	uuid := deterministicUUID("test@example.com")
	// Should be in UUID format: 8-4-4-4-12
	parts := strings.Split(uuid, "-")
	if len(parts) != 5 {
		t.Fatalf("expected 5 parts, got %d: %q", len(parts), uuid)
	}
	if len(parts[0]) != 8 || len(parts[1]) != 4 || len(parts[2]) != 4 || len(parts[3]) != 4 || len(parts[4]) != 12 {
		t.Errorf("unexpected UUID format: %q", uuid)
	}

	// Should be deterministic
	if deterministicUUID("test@example.com") != uuid {
		t.Error("expected deterministic output for same input")
	}

	// Different input should produce different output
	if deterministicUUID("other@example.com") == uuid {
		t.Error("expected different output for different input")
	}
}

