package handler

import (
	"crypto/sha256"
	"encoding/json"
	"fmt"
	"net/http"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"github.com/ketang/kapow/api/internal/auth"
)

type devLoginRequest struct {
	Email string `json:"email"`
	Name  string `json:"name"`
	Sub   string `json:"sub"`
}

type devLoginResponse struct {
	AccessToken string `json:"access_token"`
	TokenType   string `json:"token_type"`
	ExpiresIn   int    `json:"expires_in"`
}

// DevLogin returns a handler that issues HS256 JWTs for local development.
// The handler must only be registered when ENV == "development".
func DevLogin(secret string) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		var req devLoginRequest
		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
			http.Error(w, `{"error":"invalid JSON body"}`, http.StatusBadRequest)
			return
		}
		if req.Email == "" {
			http.Error(w, `{"error":"email is required"}`, http.StatusBadRequest)
			return
		}

		sub := req.Sub
		if sub == "" {
			sub = deterministicUUID(req.Email)
		}

		now := time.Now()
		const expiresIn = 24 * time.Hour

		claims := &auth.Claims{
			RegisteredClaims: jwt.RegisteredClaims{
				Subject:   sub,
				Issuer:    "kapow-dev",
				Audience:  jwt.ClaimStrings{"authenticated"},
				IssuedAt:  jwt.NewNumericDate(now),
				ExpiresAt: jwt.NewNumericDate(now.Add(expiresIn)),
			},
			Email: req.Email,
			Role:  "authenticated",
			AppMetadata: map[string]any{
				"provider": "dev",
			},
		}
		if req.Name != "" {
			claims.UserMetadata = map[string]any{
				"full_name": req.Name,
			}
		}

		token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
		signed, err := token.SignedString([]byte(secret))
		if err != nil {
			http.Error(w, `{"error":"failed to sign token"}`, http.StatusInternalServerError)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(devLoginResponse{
			AccessToken: signed,
			TokenType:   "bearer",
			ExpiresIn:   int(expiresIn.Seconds()),
		})
	}
}

// deterministicUUID generates a UUID v5-like identifier from an email address.
func deterministicUUID(email string) string {
	h := sha256.Sum256([]byte("kapow-dev:" + email))
	// Format as UUID (8-4-4-4-12)
	return fmt.Sprintf("%08x-%04x-%04x-%04x-%012x",
		h[0:4], h[4:6], h[6:8], h[8:10], h[10:16])
}

